script:
(function (root_element) {
  console.log("Initializing HR Dashboard...");

  // Set Month Name for Adherence
  let today = frappe.datetime.now_date();
  let today_date = frappe.datetime.str_to_obj(today);
  let month_name = today_date.toLocaleDateString("en-GB", {
    month: "long",
    year: "numeric",
  });

  let monthEl = root_element.querySelector("#adherence-month-name");
  if (monthEl) {
    monthEl.textContent = month_name;
  }

  // nerate last 6 months options
  function populateMonthOptions() {
    let selectEl = root_element.querySelector("#adherence-month-select");
    if (!selectEl) return;

    let today = frappe.datetime.now_date();
    let today_date = frappe.datetime.str_to_obj(today);

    for (let i = 0; i < 6; i++) {
      let d = new Date(today_date.getFullYear(), today_date.getMonth() - i, 1);
      let month_name = d.toLocaleDateString("en-GB", {
        month: "long",
        year: "numeric",
      });

      let opt = document.createElement("option");
      opt.value = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(
        2,
        "0"
      )}`; // format: 2025-09
      opt.textContent = month_name;

      if (i === 0) opt.selected = true; // current month by default
      selectEl.appendChild(opt);
    }
  }

  function loadAttendanceSummary(monthValue) {
    frappe.call({
      method: "beams.api.workspace.get_attendance_summary",
      args: { month: monthValue },
      callback: function (r) {
        if (r.message) {
          let data = r.message;
          console.log("Attendance summary data:", data); // 👀 Debug

          let options = {
            chart: {
              type: "donut",
              height: 180,
              width: 400,
            },
            series: [
              data["Present"] || 0,
              data["On Leave"] || 0,
              data["Absent"] || 0,
              data["Half Day"] || 0,
            ],
            labels: [
              `Present (${data["Present"] || 0})`,
              `On Leave (${data["On Leave"] || 0})`,
              `Absent (${data["Absent"] || 0})`,
              `Half Day (${data["Half Day"] || 0})`,
            ],
            colors: ["#00C853", "#00B0FF", "#FF3D00", "#FFC400", "#CFD8DC"],
            legend: {
              position: "right",
              fontSize: "14px",
              markers: { width: 12, height: 12 },
              itemMargin: { horizontal: 10, vertical: 8 },
              formatter: function (seriesName, opts) {
                return seriesName; // Prevents wrapping issues
              },
            },

            tooltip: { enabled: false },
            dataLabels: { enabled: false },
            plotOptions: {
              pie: {
                donut: {
                  size: "90%",
                  labels: { show: false },
                },
              },
            },
            responsive: [
              {
                breakpoint: 480,
                options: {
                  chart: { width: 250 },
                  legend: { position: "bottom" },
                },
              },
            ],
          };

          let chartContainer = root_element.querySelector("#adherence-chart");
          if (chartContainer) {
            chartContainer.innerHTML = "";
            let chart = new ApexCharts(chartContainer, options);
            chart.render();
            let total =
              (data["Present"] || 0) +
              (data["On Leave"] || 0) +
              (data["Absent"] || 0) +
              (data["Work From Home"] || 0) +
              (data["Half Day"] || 0);

            let centerNumber = chartContainer.parentElement.querySelector(
              ".donut-center .number"
            );
            let centerLabel = chartContainer.parentElement.querySelector(
              ".donut-center .label"
            );

            if (centerNumber) centerNumber.textContent = total;
            if (centerLabel) centerLabel.textContent = "Days";
          } else {
            console.error("❌ No #adherence-chart container found in DOM");
          }
        }
      },
    });
  }

  frappe.after_ajax(() => {
    populateMonthOptions();

    // load current month initially
    let selectEl = root_element.querySelector("#adherence-month-select");
    loadAttendanceSummary(selectEl.value);

    // change event
    selectEl.addEventListener("change", function () {
      loadAttendanceSummary(this.value);
    });
  });

  // andle "Add Referral" button click
  let btn_referral = root_element.querySelector("#add-referral-btn");
  if (btn_referral) {
    btn_referral.addEventListener("click", function () {
      // Generate a random ID like Frappe does
      let random_id = frappe.utils.get_random(10);
      let docname = `new-employee-referral-${random_id}`;
      let url = `/app/employee-referral/${docname}`;

      // Open in new tab
      window.open(url, "_blank").focus();
    });
  }

  // andle "Explore your weekly schedule" button click
  let btn = root_element.querySelector("#explore-schedule-btn");
  if (btn) {
    btn.addEventListener("click", function () {
      frappe.call({
        method: "beams.api.workspace.get_weekly_schedule",
        callback: function (r) {
          let html = "";

          if (r.message && r.message.length > 0) {
            html = `
                            <table class="table table-bordered table-striped">
                                <thead>
                                    <tr>
                                        <th>Date</th>
                                        <th>Day</th>
                                        <th>In Time</th>
                                        <th>Break 1</th>
                                        <th>Lunch</th>
                                        <th>Break 2</th>
                                        <th>End Time</th>
                                        <th>Status</th>
                                        <th>Remarks</th>
                                    </tr>
                                </thead>
                                <tbody>
                        `;
            r.message.forEach((row) => {
              html += `
                                <tr>
                                    <td>${row.date}</td>
                                    <td>${row.day}</td>
                                    <td>${row.in_time || "OFF"}</td>
                                    <td>${row.break1 || ""}</td>
                                    <td>${row.lunch || ""}</td>
                                    <td>${row.break2 || ""}</td>
                                    <td>${row.end_time || "OFF"}</td>
                                    <td>${row.status || "Ok"}</td>
                                    <td>${row.remarks || "Accepted"}</td>
                                </tr>
                            `;
            });
            html += "</tbody></table>";
          } else {
            html = "<p>No schedule available.</p>";
          }

          let d = new frappe.ui.Dialog({
            title: "Your Weekly Schedule",
            size: "extra-large",
            primary_action_label: "Close",
            primary_action: () => d.hide(),
          });

          d.$body.html(html);
          d.show();
        },
      });
    });
  }

  // ---------------- Time Utilization ----------------
  let breakIntervals = {};
  let activeBreakType = null;

  function parseServerDatetime(dt) {
    if (!dt) return new Date();
    if (typeof dt === "string") {
      let s = dt.replace(" ", "T");
      s = s.replace(/(\.\d{3})\d+/, "$1");
      return new Date(s);
    }
    return new Date(dt);
  }

  function formatTime(secondsFloat) {
    secondsFloat = Math.max(0, Number(secondsFloat) || 0);
    let totalSeconds = Math.floor(secondsFloat);
    let hh = String(Math.floor(totalSeconds / 3600)).padStart(2, "0");
    let mm = String(Math.floor((totalSeconds % 3600) / 60)).padStart(2, "0");
    let ss = String(totalSeconds % 60).padStart(2, "0");
    return `${hh}:${mm}:${ss}`;
  }

  function startBreakTimer(breakType, breakId, startTimeFromServer) {
    const rowEl = Array.from(root_element.querySelectorAll(".common-sm-font"))
      .find((el) => el.textContent.trim() === breakType)
      ?.closest(".col-6");
    if (!rowEl) return;

    const switchEl = rowEl.querySelector("input[type=checkbox]");
    if (switchEl) switchEl.dataset.breakId = breakId;
    const timerEl = rowEl.querySelector(".break-timer");
    const startDate = parseServerDatetime(startTimeFromServer);

    if (breakIntervals[breakType]) clearInterval(breakIntervals[breakType]);

    breakIntervals[breakType] = setInterval(() => {
      const diffSec = (Date.now() - startDate.getTime()) / 1000;
      if (timerEl) timerEl.textContent = formatTime(diffSec);
    }, 1000);

    activeBreakType = breakType;
  }

  function stopBreakTimer(breakType, totalSec) {
    if (breakIntervals[breakType]) clearInterval(breakIntervals[breakType]);
    delete breakIntervals[breakType];

    const rowEl = Array.from(root_element.querySelectorAll(".common-sm-font"))
      .find((el) => el.textContent.trim() === breakType)
      ?.closest(".col-6");
    if (!rowEl) return;

    const timerEl = rowEl.querySelector(".break-timer");
    if (timerEl) timerEl.textContent = formatTime(totalSec);

    const switchEl = rowEl.querySelector("input[type=checkbox]");
    if (switchEl) switchEl.dataset.breakId = null;

    if (activeBreakType === breakType) activeBreakType = null;
  }

  function attachSwitchListeners() {
    const switches = root_element.querySelectorAll(
      ".switch input[type=checkbox]"
    );
    switches.forEach((chk) => {
      chk.addEventListener("change", function () {
        const rowEl = this.closest(".p-2.border");
        const breakType = rowEl
          .querySelector(".common-sm-font")
          .textContent.trim();
        const isChecked = this.checked;

        if (isChecked) {
          if (activeBreakType && activeBreakType !== breakType) {
            frappe.msgprint(
              `You already have <b>${activeBreakType}</b> running. Please stop it first.`
            );
            this.checked = false;
            return;
          }

          frappe.call({
            method: "beams.api.workspace.get_today_checkin_status",
            callback: (res) => {
              const status = res.message?.status;

              if (!status || status === "NO_CHECKIN") {
                frappe.msgprint(
                  "You must check in today before starting a break."
                );
                chk.checked = false;
                return;
              }

              if (status === "OUT") {
                // ✅ Only block if the last action today is checkout
                frappe.msgprint(
                  "Your last action today is a checkout. Cannot start a break."
                );
                chk.checked = false;
                return;
              }

              if (status === "IN") {
                // ✅ Allow break
                frappe.confirm(
                  `Are You Sure to Turn <b>${breakType}</b> Timer On?`,
                  () => {
                    frappe.call({
                      method: "beams.api.workspace.start_break",
                      args: { break_type: breakType },
                      callback: (r) => {
                        if (r.message && r.message.success) {
                          frappe.show_alert({
                            message: `${breakType} started`,
                            indicator: "green",
                          });
                          startBreakTimer(
                            breakType,
                            r.message.break_id,
                            r.message.start_time
                          );
                        } else {
                          frappe.msgprint(
                            r.message?.message || "Error starting break"
                          );
                          chk.checked = false;
                        }
                      },
                    });
                  },
                  () => {
                    chk.checked = false;
                  }
                );
              }
            },
          });
        } else {
          const breakId = chk.dataset.breakId;
          if (!breakId) {
            chk.checked = false;
            return;
          }

          frappe.call({
            method: "beams.api.workspace.stop_break",
            args: { break_id: breakId },
            callback: (r) => {
              if (r.message?.success) {
                frappe.show_alert({
                  message: `${breakType} stopped`,
                  indicator: "orange",
                });
                stopBreakTimer(breakType, r.message.total_duration || 0);
              } else {
                frappe.msgprint(r.message?.message || "Error stopping break");
              }
            },
          });
        }
      });
    });
  }

  function initializeUserInfo() {
    const userTimeZone = frappe.sys_defaults.time_zone || "UTC";

    // Log the retrieved timezone to your browser console to verify its value!
    console.log("User Timezone Retrieved:", userTimeZone);

    // --- Last Logged (Formatted by Frappe's Utility) ---
    frappe.call({
      method: "frappe.client.get_value",
      args: {
        doctype: "User",
        filters: { name: frappe.session.user },
        fieldname: "last_login",
      },
      callback: function (r) {
        if (r.message && r.message.last_login) {
          let utcDate = new Date(r.message.last_login);
          let localDateStr = utcDate.toLocaleString("en-GB", {
            timeZone: frappe.sys_defaults.time_zone || "UTC",
            year: "numeric",
            month: "2-digit",
            day: "2-digit",
            hour: "2-digit",
            minute: "2-digit",
            second: "2-digit",
            hour12: false,
          });
          let [date_str, time_str] = localDateStr.split(", ");
          const timeEl = root_element.querySelector("#last_logged");
          if (timeEl) timeEl.textContent = time_str;
          const dateEl = root_element.querySelector("#last_logged_date");
          if (dateEl) dateEl.textContent = date_str;
        }
      },
    });

    // ----------------------------------------------------------------------

    // --- EST Clock (Hardcoded) ---
    setInterval(() => {
      let now = new Date();
      let est_time = now.toLocaleString("en-GB", {
        timeZone: "America/New_York",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false,
      });
      const el = root_element.querySelector("#est_time");
      if (el) el.textContent = est_time;
    }, 1000);

    // ----------------------------------------------------------------------

    // --- User's Local Clock (Based on User's Timezone Setting) ---
    setInterval(() => {
      let now = new Date();
      // Use the reliably retrieved userTimeZone variable
      let local_time = now.toLocaleString("en-GB", {
        timeZone: userTimeZone, // <-- This MUST be "Asia/Seoul" to work correctly
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false,
      });

      const el = root_element.querySelector("#local_time");
      if (el) el.textContent = local_time;
    }, 1000);

    // ----------------------------------------------------------------------

    // --- Today’s Date (Based on User's Timezone) ---

    // Get the current date string in the user's timezone for accurate day rollover
    let date_str_in_tz = new Date().toLocaleString("en-US", {
      timeZone: userTimeZone,
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
    });

    // Create a new Date object from the string (needed because Date() always starts in browser TZ)
    let today_date = new Date(date_str_in_tz);

    let formatted_date = today_date.toLocaleDateString("en-GB", {
      day: "2-digit",
      month: "long",
      year: "numeric",
    });

    const el = root_element.querySelector("#today_date");
    if (el) el.textContent = formatted_date;
  }
  // ---------------- Init ----------------
  attachSwitchListeners();
  initializeUserInfo();

  // Redirect "More" button to schedule-adherence page
})(root_element);

