script:
(function() {
    // -------------------------------
    // Attendance Card Functions
    // -------------------------------

    function startWorkTimer(root_element, checkinTime, is_resume = false) {
        let workHoursEl = root_element.querySelector(".work-hours");

        // Ensure baseline
        if (root_element.totalWorkedSeconds === undefined || !is_resume) {
            root_element.totalWorkedSeconds = root_element.totalWorkedSeconds || 0;
        }

        function updateTimer() {
            let now = new Date();
            if (!checkinTime || isNaN(checkinTime.getTime())) return;

            let elapsed = Math.floor((now - checkinTime) / 1000);
            let total = root_element.totalWorkedSeconds + elapsed;

            let hours = String(Math.floor(total / 3600)).padStart(2, '0');
            let minutes = String(Math.floor((total % 3600) / 60)).padStart(2, '0');
            let seconds = String(total % 60).padStart(2, '0');

            if (workHoursEl) {
                workHoursEl.textContent = `${hours}:${minutes}:${seconds}`;
            }
        }

        // Clear old interval
        if (root_element.workTimerInterval) {
            clearInterval(root_element.workTimerInterval);
        }

        updateTimer();
        root_element.workTimerInterval = setInterval(updateTimer, 1000);
    }

    function updateLabel(root_element, labelText, datetime) {
        if (!datetime) return;

        const dt = new Date(datetime);
        if (isNaN(dt.getTime())) return;

        const labels = root_element.querySelectorAll(".label");
        for (let label of labels) {
            if (label.textContent.trim() === labelText) {
                let el = label.closest(".text-center").querySelector(".break-info");
                if (el) {
                    el.textContent = dt.toLocaleTimeString('en-US', {
                        hour: '2-digit',
                        minute: '2-digit',
                        hour12: true
                    });
                    el.dataset.label = labelText;
                    el.dataset.datetime = dt.toISOString();
                }
            }
        }
    }

    function updateValue(root_element, label, value) {
        let cards = root_element.querySelectorAll(".availability-card");
        cards.forEach(card => {
            let title = card.querySelector(".card-title");
            if (title && title.textContent.trim() === label) {
                let valueEl = card.querySelector(".card-value");
                if (valueEl) {
                    valueEl.childNodes[0].textContent = value + " ";
                }
            }
        });
    }

    // -------------------------------
    // Attendance + Availability Initialization
    // -------------------------------

    let today = frappe.datetime.now_date(); // "YYYY-MM-DD"
    let today_date = frappe.datetime.str_to_obj(today);

    // Attendance date header
    let formatted_date = today_date.toLocaleDateString('en-GB', {
        day: '2-digit',
        month: 'long',
        year: 'numeric'
    });
    let dateEl = root_element.querySelector("#attendance-date");
    if (dateEl) {
        dateEl.innerHTML = `${formatted_date} <span class="badge ms-2 p-1 px-2 common_badge_color">Today</span>`;
    }

    // Availability month header
    let month_name = today_date.toLocaleDateString('en-GB', {
        month: 'long',
        year: 'numeric'
    });
    let monthEl = root_element.querySelector("#month-name");
    if (monthEl) {
        monthEl.textContent = month_name;
    }

    // --- Fetch Attendance ---
    frappe.call({
        method: "beams.api.workspace.get_today_checkin_status",
        callback: function(r) {
            let btn = root_element.querySelector(".btn-punch");
            let workHoursEl = root_element.querySelector(".work-hours");

            if (r.message) {
                let { first_checkin, last_checkin, last_checkout, worked_seconds } = r.message;

                // Checked In label should always show first checkin
                if (first_checkin) updateLabel(root_element, "Checked In", first_checkin);
                if (last_checkout) updateLabel(root_element, "Checked Out", last_checkout);

                if (worked_seconds !== undefined) {
                    root_element.totalWorkedSeconds = worked_seconds;
                    workHoursEl.textContent = new Date(worked_seconds * 1000)
                        .toISOString()
                        .substr(11, 8);
                }

                if (!first_checkin || last_checkout) {
                    // Show Check In button
                    btn.classList.remove("btn-outline-danger");
                    btn.classList.add("btn-outline-success");
                    btn.innerHTML = `<i class="fa fa-sign-in"></i> Check In`;
                    btn.dataset.action = "IN";
                } else {
                    // Running timer from last checkin
                    startWorkTimer(root_element, new Date(last_checkin), true);
                    btn.classList.remove("btn-outline-success");
                    btn.classList.add("btn-outline-danger");
                    btn.innerHTML = `<i class="fa fa-sign-out"></i> Check Out`;
                    btn.dataset.action = "OUT";
                }
            }
        }
    });

    // --- Punch In/Out handler ---
    root_element.querySelector(".btn-punch").addEventListener("click", function() {
        let action = this.dataset.action;

        frappe.call({
            method: "beams.api.workspace.mark_checkin",
            args: { log_type: action },
            callback: function(r) {
                if (r.message && r.message.success) {
                    frappe.show_alert({
                        message: `Punch ${action} recorded`,
                        indicator: "green"
                    });

                    let now = new Date();
                    let btn = root_element.querySelector(".btn-punch");

                    if (action === "IN") {
                        // Start timer fresh from now
                        startWorkTimer(root_element, now, false);

                        btn.classList.remove("btn-outline-success");
                        btn.classList.add("btn-outline-danger");
                        btn.innerHTML = `<i class="fa fa-sign-out"></i> Check Out`;
                        btn.dataset.action = "OUT";
                        if (r.message.first_checkin) {
                            updateLabel(root_element, "Checked In", r.message.first_checkin);
                        }

                    } else if (action === "OUT") {
                        // Stop timer
                        if (root_element.workTimerInterval) {
                            clearInterval(root_element.workTimerInterval);
                        }

                        // Convert JS Date "now" to user's timezone string
                        let nowInUserTZ = frappe.datetime.convert_to_user_tz(new Date().toISOString(), "UTC");

                        // Convert nowInUserTZ string back to JS Date for calculations
                        let nowDateObj = frappe.datetime.str_to_obj(nowInUserTZ);

                        // Add duration of current session using last_checkin
                        if (r.message.last_checkin) {
                            let checkinTime = frappe.datetime.str_to_obj(r.message.last_checkin); // JS Date object
                            if (!isNaN(checkinTime.getTime()) && !isNaN(nowDateObj.getTime())) {
                                let elapsedSeconds = Math.floor((nowDateObj - checkinTime) / 1000);
                                root_element.totalWorkedSeconds = (root_element.totalWorkedSeconds || 0) + elapsedSeconds;
                            }
                        }

                        // Update final time on screen
                        let workHoursEl = root_element.querySelector(".work-hours");
                        if (workHoursEl) {
                            workHoursEl.textContent = new Date(root_element.totalWorkedSeconds * 1000)
                                .toISOString()
                                .substr(11, 8);
                        }

                        // Update button
                        let btn = root_element.querySelector(".btn-punch");
                        btn.classList.remove("btn-outline-danger");
                        btn.classList.add("btn-outline-success");
                        btn.innerHTML = `<i class="fa fa-sign-in"></i> Check In`;
                        btn.dataset.action = "IN";

                        // Show Checked Out label in user timezone
                        updateLabel(root_element, "Checked Out", nowInUserTZ);
                    }

                }
            }
        });
    });

    // -------------------------------
    // Fetch Availability Data (Present/Absent)
    // -------------------------------
    frappe.call({
        method: "beams.api.workspace.get_employee_attendance",
        callback: function(r) {
            if (r.message) {
                updateValue(root_element, "Present", r.message.present);
                updateValue(root_element, "Absent", r.message.absent);
            }
        }
    });

    // -------------------------------
    // Fetch Adherence %
    // -------------------------------
    frappe.call({
        method: "beams.api.workspace.get_employee_adherence",
        callback: function(r) {
            if (r.message && r.message.adherence !== undefined) {
                updateValue(root_element, "Adherence(%)", r.message.adherence + "%");
            }
        }
    });

    // -------------------------------
    // Fetch Shrinkage %
    // -------------------------------
    frappe.call({
        method: "beams.api.workspace.get_employee_shrinkage",
        callback: function(r) {
            if (r.message && r.message.shrinkage !== undefined) {
                updateValue(root_element, "Shrinkage(%)", r.message.shrinkage + "%");
            }
        }
    });

})();

