script:
(function() {
    function getGreetingByTime() {
        const hour = new Date().getHours();
        if (hour < 12) return "Good Morning";
        else if (hour < 17) return "Good Afternoon";
        else return "Good Evening";
    }

    function updateUserGreeting(root_element) {
        if (typeof frappe !== 'undefined' && frappe.session) {
            const userFullName = frappe.session.user_fullname || frappe.session.user;
            const welcomeUserEl = root_element.querySelector('.welcome_title');
            if (welcomeUserEl) {
                const greeting = getGreetingByTime();
                welcomeUserEl.textContent = `${greeting} ${userFullName} 👋,`;
            }
        }
    }

    function setupEmojiClicks(root_element, alreadyMarkedEmoji = null) {
        const emojiDivs = root_element.querySelectorAll('.mood-emoji');

        emojiDivs.forEach(emoji => {
            emoji.style.cursor = 'pointer';
            emoji.style.transition = 'transform 0.2s ease';

            // If emoji already marked, disable further clicks
            if (alreadyMarkedEmoji) {
                if (emoji.textContent.trim() === alreadyMarkedEmoji) {
                    emoji.classList.add('emoji-selected');
                    emoji.style.transform = 'scale(1.5)';
                }
                emoji.style.pointerEvents = 'none';
                return;
            }

            emoji.addEventListener('click', (event) => {
                const chosenEmoji = event.currentTarget.textContent.trim();

                // Remove previous selection classes and reset scale
                emojiDivs.forEach(e => {
                    e.classList.remove('emoji-selected');
                    e.style.transform = 'scale(1)';
                });

                // Apply selection effect
                const selected = event.currentTarget;
                selected.classList.add('emoji-selected');
                selected.style.transform = 'scale(1.5)';

                // Disable all emojis so user can't click again
                emojiDivs.forEach(e => e.style.pointerEvents = 'none');

                // Save mood to backend
                frappe.call({
                    method: "beams.api.workspace.set_employee_mood",
                    args: { mood: chosenEmoji }
                });
            });
        });
    }

    function loadEmployeeMood(root_element) {
        frappe.call({
            method: "beams.api.workspace.get_employee_mood",
            callback: function(r) {
                if (r.message && r.message.mood) {
                    // Initialize emoji clicks but disable further selection
                    setupEmojiClicks(root_element, r.message.mood);
                } else {
                    setupEmojiClicks(root_element);
                }
            }
        });
    }

    // Only initialize if root_element is defined
    if (typeof root_element !== 'undefined') {
        updateUserGreeting(root_element);
        loadEmployeeMood(root_element);
    }
})();

