script:
frappe.after_ajax(() => {
  const container = root_element.querySelector("#employee-content");
  container.innerHTML = `<p class="text-muted">Loading all employees...</p>`;

  frappe.call({
    method: "frappe.client.get_list",
    args: {
      doctype: "Employee",
      fields: [
        "name",
        "employee_name",
        "designation",
        "status",
        "department",
        "date_of_joining",
        "image"
      ],
      order_by: "modified DESC", // fallback ordering
      limit_page_length: 500
    },
    callback: function (res) {
      const employees = res.message || [];
      container.innerHTML = "";

      if (employees.length === 0) {
        container.innerHTML = `<p class="text-muted">No employees found.</p>`;
        return;
      }

      // Group employees by department
      const grouped = {};
      employees.forEach(emp => {
        if (!grouped[emp.department]) grouped[emp.department] = [];
        grouped[emp.department].push(emp);
      });

      // Sort department names alphabetically and employees within by DOJ DESC
      Object.keys(grouped).sort().forEach(dept => {
        grouped[dept].sort((a, b) => {
          const dojA = new Date(a.date_of_joining?.split(" ")[0] || "1970-01-01");
          const dojB = new Date(b.date_of_joining?.split(" ")[0] || "1970-01-01");
          return dojB - dojA; // Newest first
        });

        // Add department header
        const deptHeader = document.createElement("h5");
        deptHeader.className = "text-primary mt-4 mb-2";
        deptHeader.textContent = `🏢 ${dept || "No Department"}`;
        container.appendChild(deptHeader);

        // Append employee cards
        grouped[dept].forEach(emp => {
          const div = createEmployeeCard(emp);
          container.appendChild(div);
          fetchExternalWorkHistory(emp.name, div);
        });
      });
    }
  });

  // Employee card creator
  function createEmployeeCard(emp) {
    const div = document.createElement("div");
    div.className = "item-card";
    div.innerHTML = `
      <div class="d-flex align-items-start">
        <img src="${emp.image || '/files/default-avatar.png'}"
             onerror="this.onerror=null;this.src='/files/default-avatar.png';"
             alt="" class="employee-photo">
        <div class="flex-grow-1">
          <div class="item-header d-flex justify-content-between">
            <div class="item-title fw-bold">${emp.employee_name}</div>
            <div class="item-date">${emp.date_of_joining?.split(" ")[0] || "No DOJ"}</div>
          </div>
          <div class="item-details text-muted">${emp.designation || "No Designation"}</div>
          <div class="item-meta d-flex justify-content-between mt-2 mb-2">
            <div class="meta-item">🏢 ${emp.department || "N/A"}</div>
            <div class="meta-item">
              <span class="badge ${emp.status === "Active" ? "bg-success" : "bg-secondary"}">${emp.status}</span>
            </div>
          </div>
          <div class="external-history">
            <p class="text-muted mb-1"><strong>Previous Work History:</strong></p>
            <div class="history-items">Loading...</div>
          </div>
        </div>
      </div>
    `;
    return div;
  }

  // Fetch work history
  function fetchExternalWorkHistory(empName, div) {
    frappe.call({
      method: "frappe.client.get",
      args: {
        doctype: "Employee",
        name: empName
      },
      callback: function (empFull) {
        const doc = empFull.message;
        const childRecords = doc.external_work_history || [];
        const historyContainer = div.querySelector(".history-items");

        if (childRecords.length > 0) {
          historyContainer.innerHTML = childRecords.map(row => `
            <div class="border rounded p-2 mb-1" style="background-color: #f0f2f5;">
              <div><strong>Company:</strong> ${row.company_name}</div>
              <div><strong>Designation:</strong> ${row.designation}</div>
              <div><strong>Salary:</strong> ₹${row.salary}</div>
              <div><strong>Address:</strong> ${row.address}</div>
            </div>
          `).join("");
        } else {
          historyContainer.innerHTML = `<div class="text-muted">No external work history found.</div>`;
        }
      }
    });
  }
});

