script:
(function () {
  if (typeof root_element === "undefined" || !root_element) {
    console.error("The 'root_element' variable is not available.");
    return;
  }

  // ---------------------------
  // Manual Tab Switching
  // ---------------------------
  // This code uses data-toggle, which is for Bootstrap 4.
  // However, it's manually handling the logic, so it will still work even with Bootstrap 5.
  const tabButtons = root_element.querySelectorAll(
    'button[data-bs-toggle="tab"]'
  );
  tabButtons.forEach((tabBtn) => {
    tabBtn.addEventListener("click", function (e) {
      e.preventDefault();

      const parentCard = this.closest(".card");
      parentCard
        .querySelectorAll(".nav-link")
        .forEach((btn) => btn.classList.remove("active"));
      parentCard
        .querySelectorAll(".tab-pane")
        .forEach((pane) => pane.classList.remove("show", "active"));

      this.classList.add("active");
      const tabTarget = this.getAttribute("data-bs-target");
      if (tabTarget) {
        const pane = parentCard.querySelector(tabTarget);
        if (pane) {
          pane.classList.add("show", "active");
        }
      }
    });
  });

  // ---------------------------
  // Important Links - Holiday List Modal
  // ---------------------------
  root_element.addEventListener("click", function (e) {
    let link = e.target.closest("a.open-holiday-list");
    if (link) {
      e.preventDefault();

      // Only append modal if it isn't there already
      if ($("#holidayListModal").length === 0) {
        $("body").append(`
                    <div class="modal fade" id="holidayListModal" tabindex="-1" role="dialog" aria-labelledby="holidayListModalLabel" aria-hidden="true">
                        <div class="modal-dialog modal-lg" role="document">
                            <div class="modal-content">
                                <div class="modal-header">
                                    <h4 class="modal-title" id="holidayListModalLabel">Holiday List 2025</h4>
                                    <button type="button" class="btn-close border-none" data-dismiss="modal" aria-label="Close">
                                        <svg class="icon icon-sm" aria-hidden="true">
                                            <use class="close-alt" href="#icon-close-alt"></use>
                                        </svg>
                                    </button>
                                </div>
                                <div class="modal-body">
                                    <div id="holiday-list-content">Loading...</div>
                                </div>
                            </div>
                        </div>
                    </div>
                `);
      }

      $("#holidayListModal").modal("show");
      $("#holiday-list-content").html("Loading...");

      // Get Holiday List assigned to Employee
      frappe.call({
        method: "frappe.client.get_value",
        args: {
          doctype: "Employee",
          filters: { user_id: frappe.session.user },
          fieldname: "holiday_list",
        },
        callback: function (res) {
          if (res && res.message && res.message.holiday_list) {
            let holiday_list_name = res.message.holiday_list;
            frappe.call({
              method: "beams.api.workspace.get_holidays_by_list_name",
              args: { holiday_list_name: holiday_list_name },
              callback: function (r) {
                if (r.message && r.message.length > 0) {
                  let html = `
                                        <table class="table table-bordered table-striped">
                                            <thead>
                                                <tr>
                                                    <th>SL. No.</th>
                                                    <th>Holiday For</th>
                                                    <th>Holiday Date</th>
                                                    <th>Nature of Holiday</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                    `;
                  r.message.forEach(function (holiday, index) {
                    html += `
                                            <tr>
                                                <td>${index + 1}</td>
                                                <td>${
                                                  holiday.description || ""
                                                }</td>
                                                <td>${frappe.format(
                                                  holiday.holiday_date,
                                                  { fieldtype: "Date" }
                                                )}</td>
                                                <td>${
                                                  holiday.weekly_off
                                                    ? "Statutory Holiday"
                                                    : "Festive"
                                                }</td>
                                            </tr>
                                        `;
                  });
                  html += "</tbody></table>";
                  $("#holiday-list-content").html(html);
                } else {
                  $("#holiday-list-content").html(
                    `<p>No holidays found in Holiday List: ${holiday_list_name}.</p>`
                  );
                }
              },
            });
          } else {
            $("#holiday-list-content").html(
              "<p>No Holiday List is assigned to your Employee record.</p>"
            );
          }
        },
      });
    }
  });

  // ---------------------------
  // Leave Tab - Load Data
  // ---------------------------
  root_element
    .querySelector("#leave-tab")
    .addEventListener("click", function () {
      const leaveContainer = root_element.querySelector("#leave");
      leaveContainer.innerHTML = '<p class="px-2 py-2">Loading leaves...</p>';

      frappe.call({
        method: "beams.api.workspace.get_absent_days",
        args: {}, // No user_id to get all employees on leave today
        callback: function (r) {
          if (r.message && r.message.length > 0) {
            let html = "";

            // Fetch employee details for each leave record
            let employeePromises = r.message.map((row) => {
              return new Promise((resolve) => {
                frappe.call({
                  method: "frappe.client.get_value",
                  args: {
                    doctype: "Employee",
                    filters: { name: row.employee },
                    fieldname: [
                      "employee_name",
                      "image",
                      "department",
                      "designation",
                    ],
                  },
                  callback: function (empRes) {
                    resolve({
                      ...row,
                      employee_name:
                        empRes.message?.employee_name || row.employee,
                      image:
                        empRes.message?.image ||
                        "/assets/frappe/images/default-avatar.png",
                      department: empRes.message?.department || "",
                      designation: empRes.message?.designation || "",
                    });
                  },
                });
              });
            });

            Promise.all(employeePromises).then((enrichedLeaves) => {
              enrichedLeaves.forEach((row) => {
                const statusBadge =
                  row.workflow_state || row.status || "Pending";
                const statusClass =
                  statusBadge === "Approved"
                    ? "common_success"
                    : statusBadge === "Rejected"
                    ? "text-danger"
                    : "common_applied";

                html += `
                  <div class="d-flex justify-content-between px-2 py-2 align-items-center border-bottom">
                    <div class="d-flex align-items-center">
                      <img src="${
                        row.image
                      }" class="rounded-circle mr-2" width="32" height="32" alt="Avatar">
                      <div>
                        <div><b>${row.employee_name}</b></div>
                        <div class="small text-muted">${row.leave_type}</div>
                        <div class="small text-muted">${frappe.format(
                          row.from_date,
                          { fieldtype: "Date" }
                        )} to ${frappe.format(row.to_date, {
                  fieldtype: "Date",
                })}</div>
                      </div>
                    </div>
                    <div class="${statusClass}" style="font-size: 12px;">
                      ${statusBadge}
                    </div>
                  </div>`;
              });
              leaveContainer.innerHTML = html;
            });
          } else {
            leaveContainer.innerHTML =
              '<p class="px-2 py-2">No one is on leave today 🎉</p>';
          }
        },
      });
    });

  // ---------------------------
  // Birthday Tab
  // ---------------------------
  root_element
    .querySelector("#birthday-tab")
    .addEventListener("click", function () {
      const birthdayContainer = root_element.querySelector("#birthday");
      birthdayContainer.innerHTML =
        '<p class="px-2 py-2">Loading birthdays...</p>';

      frappe.call({
        method: "beams.api.workspace.get_today_birthdays",
        callback: function (r) {
          if (r.message) {
            let html = "";
            r.message.forEach((row) => {
              const img =
                row.image || "/assets/frappe/images/default-avatar.png";
              html += `
                            <div class="d-flex justify-content-between px-2 py-2 align-items-center border-bottom">
                                <div class="d-flex align-items-center">
                                    <img src="${img}" class="rounded-circle mr-2" width="32" height="32" alt="Avatar">
                                    <div>
                                        <div><b>${row.employee_name}</b></div>
                                        <div class="small text-muted">(${
                                          row.department || ""
                                        }${
                row.designation ? ", " + row.designation : ""
              })</div>
                                    </div>
                                </div>
                                <div>
                                    <img src="/assets/beams/images/birthday_cake.jpg" alt="Birthday" width="20" height="20">
                                </div>
                            </div>`;
            });
            if (!html) {
              html = `<div class="px-2 py-2">No birthdays today 🎉</div>`;
            }
            birthdayContainer.innerHTML = html;
          }
        },
      });
    });

  // ---------------------------
  // Anniversary Tab
  // ---------------------------
  root_element
    .querySelector("#anniversary-tab")
    .addEventListener("click", function () {
      const anniversaryContainer = root_element.querySelector("#anniversary");
      anniversaryContainer.innerHTML =
        '<p class="px-2 py-2">Loading anniversaries...</p>';

      frappe.call({
        method: "beams.api.workspace.get_today_anniversaries",
        callback: function (r) {
          if (r.message) {
            let html = "";
            r.message.forEach((row) => {
              const img =
                row.image || "/assets/frappe/images/default-avatar.png";
              html += `
                            <div class="d-flex justify-content-between px-2 py-2 align-items-center border-bottom">
                                <div class="d-flex align-items-center">
                                    <img src="${img}" class="rounded-circle mr-2" width="32" height="32" alt="Avatar">
                                    <div>
                                        <div><b>${row.employee_name}</b></div>
                                        <div class="small text-muted">(${
                                          row.department || ""
                                        }${
                row.designation ? ", " + row.designation : ""
              })</div>
                                    </div>
                                </div>
                                <div>
                                    <img src="/assets/beams/images/birthday_cake.jpg" alt="Anniversary" width="20" height="20">
                                </div>
                            </div>`;
            });
            if (!html) {
              html = `<div class="px-2 py-2">No anniversaries today 🎉</div>`;
            }
            anniversaryContainer.innerHTML = html;
          }
        },
      });
    });
  root_element.querySelector("#leave-tab").click();
})();




// Show Available Leaves
let btn = root_element.querySelector(".view-leave");

if (btn) {
    btn.addEventListener("click", function () {

        // 1. Get Employee from current user
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Employee",
                filters: { user_id: frappe.session.user },
                fields: ["name"],
                limit_page_length: 1
            },
            callback: function (emp_res) {
                let employee =
                    emp_res.message?.length ? emp_res.message[0].name : null;

                if (!employee) {
                    frappe.msgprint("No Employee record linked to your User.");
                    return;
                }

                // 2. Fetch Leave Details using Employee ID
                frappe.call({
                    method: "hrms.hr.doctype.leave_application.leave_application.get_leave_details",
                    args: {
                        employee: employee,
                        date: frappe.datetime.get_today()
                    },
                    callback: function (r) {
                        let html = "";
                        let data = r.message?.leave_allocation || {};

                        if (Object.keys(data).length > 0) {
                            html = `
                                <table class="table table-bordered small">
                                    <thead>
                                        <tr>
                                            <th style="width: 16%">Leave Type</th>
                                            <th style="width: 16%" class="text-right">Total Allocated Leaves</th>
                                            <th style="width: 16%" class="text-right">Expired Leaves</th>
                                            <th style="width: 16%" class="text-right">Used Leaves</th>
                                            <th style="width: 16%" class="text-right">Leaves Pending Approval</th>
                                            <th style="width: 16%" class="text-right">Available Leaves</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                            `;

                            Object.entries(data).forEach(([key, value]) => {
                                let color =
                                    value.remaining_leaves > 0
                                        ? "green"
                                        : "red";

                                html += `
                                    <tr>
                                        <td>${key}</td>
                                        <td class="text-right">${value.total_leaves}</td>
                                        <td class="text-right">${value.expired_leaves}</td>
                                        <td class="text-right">${value.leaves_taken}</td>
                                        <td class="text-right">${value.leaves_pending_approval}</td>
                                        <td class="text-right" style="color:${color}">${value.remaining_leaves}</td>
                                    </tr>
                                `;
                            });

                            html += `</tbody></table>`;
                        } else {
                            html = `<p>No leaves have been allocated.</p>`;
                        }

                        // 3. Show Dialog
                        let d = new frappe.ui.Dialog({
                            title: "Available Leaves",
                            size: "extra-large",
                            primary_action_label: "Close",
                            primary_action: () => d.hide()
                        });

                        d.$body.html(html);
                        d.show();
                    }
                });
            }
        });
    });
}

